from src.nodes.base import BaseNode

async def execute(self, inputs):
    name = inputs.get('list_name') or self.get_parameter('list_name', '')
    provided = inputs.get('list')
    if provided is None or provided == []:
        lst = BaseNode.memory.get(name) if name else None
    else:
        lst = provided

    idx = inputs.get('index')
    if idx is None:
        idx = self.get_parameter('index', 0)
    try:
        i = int(idx)
    except Exception:
        i = 0

    item = None
    success = False
    try:
        if lst is not None:
            item = lst[i]
            success = True
        else:
            self.log_info('No list available to get item from')
    except Exception as e:
        self.log_info(f'Index error: {e}')
        item = None
        success = False

    await self.set_output('item', item)
    await self.set_output('success', success)
    await self.set_output('exec_out', True)
    return {'item': item, 'success': success}
